import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { BOAT_TYPE_LABELS, Boat, BoatType } from '../../core/models';

@Component({
  selector: 'app-practice-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './practice-form.component.html',
  styleUrl: './practice-form.component.css',
})
export class PracticeFormComponent {
  private fb = inject(FormBuilder);
  private id = inject(ActivatedRoute).snapshot.paramMap.get('id');

  readonly isEdit = !!this.id;

  // Fleet available for assignment.
  boats = signal<Boat[]>([
    { id: 'b1', name: 'Morning Star', type: 'ONE_X', seats: 1, status: 'active' },
    { id: 'b2', name: 'Twin Oars', type: 'TWO_X', seats: 2, status: 'active' },
    { id: 'b3', name: 'Quad Squad', type: 'FOUR_PLUS', seats: 5, status: 'maintenance' },
    { id: 'b4', name: 'The Octet', type: 'EIGHT_PLUS', seats: 9, status: 'active' },
  ]);

  selectedBoatIds = signal<string[]>(this.isEdit ? ['b4'] : []);

  form = this.fb.group({
    startsAt: [this.isEdit ? '2026-07-15T06:00' : '', [Validators.required]],
    capacity: [this.isEdit ? 8 : 8, [Validators.required, Validators.min(1)]],
    notes: [this.isEdit ? 'Steady-state endurance row' : ''],
  });

  boatLabel(t: BoatType): string {
    return BOAT_TYPE_LABELS[t];
  }

  isSelected(id: string): boolean {
    return this.selectedBoatIds().includes(id);
  }

  toggleBoat(id: string): void {
    this.selectedBoatIds.update((ids) =>
      ids.includes(id) ? ids.filter((x) => x !== id) : [...ids, id],
    );
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
    }
    // service_agent wires this to ApiService.createPractice / updatePractice.
  }
}
